import requests, json; base='http://nv-query:8000'; h={'Authorization': 'Bearer test', 'X-Dev-Tenant': 'dev-tenant', 'X-Dev-User': 'admin'}; print('\n--- 1. Get Cases ---'); r=requests.get(f'{base}/cases', headers=h); print(r.status_code); cases=r.json().get('cases', []); print([c['title'] for c in cases]); cid=cases[0]['id'] if cases else None; print(f'\n--- 2. Create Task for {cid} ---'); r=requests.post(f'{base}/api/case/{cid}/task', headers=h, json={'title': 'Analyze Malware'}); print(r.status_code, r.text); tid=r.json().get('task_id'); print(f'\n--- 3. Create Task Log for {tid} ---'); r=requests.post(f'{base}/api/case/task/{tid}/log', headers=h, json={'body': 'Malware analysis complete.'}); print(r.status_code, r.text); print(f'\n--- 4. Export Case {cid} ---'); r=requests.get(f'{base}/api/case/{cid}/export', headers=h); print(r.status_code, r.text[:200])
